 import { useCallback, useState } from "react";
 import type { Hook, HookExecutionStatusEntry } from "../types";

 interface HookListItemProps {
 	hook: Hook;
 	executionStatus?: HookExecutionStatusEntry;
 	onToggle: (id: string, enabled: boolean) => void;
 	onDelete: (id: string) => void;
 	onEdit: (hook: Hook) => void;
 	className?: string;
 }

 export const HookListItem = ({
 	executionStatus,
 	hook,
 	onToggle,
 	onDelete,
 	onEdit,
 	className,
 }: HookListItemProps) => {
 	const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

 	const handleToggle = useCallback(() => {
 		onToggle(hook.id, !hook.enabled);
 	}, [hook.id, hook.enabled, onToggle]);

 	const handleEdit = useCallback(() => {
 		onEdit(hook);
 	}, [hook, onEdit]);

 	const handleDeleteClick = useCallback(() => {
 		setShowDeleteConfirm(true);
 	}, []);

 	const handleDeleteConfirm = useCallback(() => {
 		onDelete(hook.id);
 		setShowDeleteConfirm(false);
 	}, [hook.id, onDelete]);

 	const handleDeleteCancel = useCallback(() => {
 		setShowDeleteConfirm(false);
 	}, []);

 	// Format trigger display
 	const triggerDisplay = `${hook.trigger.agent}/${hook.trigger.operation}`;

 	// Format action display
 	const getActionDisplay = (): string => {
 		switch (hook.action.type) {
 			case "agent":
 				return `Agent: ${(hook.action.parameters as { command: string }).command}`;
 			case "git":
 				return `Git: ${(hook.action.parameters as { operation: string }).operation}`;
 			case "github":
 				return `GitHub: ${(hook.action.parameters as { operation: string }).operation}`;
 			case "custom":
 				return `Custom: ${(hook.action.parameters as { agentName: string }).agentName}`;
 			default:
 				return hook.action.type;
 		}
 	};

 	// Render timing badge
 	const renderTimingBadge = () => {
 		const timing = hook.trigger.timing || "after"; // Default to "after" for backward compatibility
 		const isBlocking = timing === "before" && hook.trigger.waitForCompletion;

 		const timingColors = {
 			before: "text-[color:var(--vscode-charts-blue,#3794ff)]",
 			after: "text-[color:var(--vscode-charts-green,#89d185)]",
 		};

 		let tooltipText = "Runs after operation completes";
 		if (timing === "before") {
 			tooltipText = isBlocking
 				? "Runs before operation and blocks until complete"
 				: "Runs before operation (non-blocking)";
