 	cloudProviderCount: 0,
 	generatedAt: 0,
 	degradedReasons: [],
 };

 const BUCKETS: Array<{ key: Bucket; label: string; empty: string }> = [
 	{
 		key: "active",
 		label: "Active",
 		empty: "No sessions are actively running.",
