 	const [snapshot, setSnapshot] = useState<Snapshot>(EMPTY_SNAPSHOT);
 	const [isLoading, setIsLoading] = useState(true);

 	useEffect(() => {
 		const onMessage = (event: MessageEvent) => {
 			const message = event.data as { type?: string; payload?: unknown };
