 						type: "orchestration/open-existing-surface",
 						payload: { source: "agent-chat" },
 					}),
 			};
 		}

 		if (
 			snapshot.degradedReasons.some((reason) =>
 				reason.includes("No cloud agent providers are registered")
 			)
 		) {
